import React, { useState, useEffect } from 'react';
import Navbar from '../components/common/Navbar';
import { systemService } from '../services/systemService';

const Systems = () => {
  const [systems, setSystems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadSystems();
  }, []);

  const loadSystems = async () => {
    try {
      const data = await systemService.getAll();
      setSystems(data);
    } catch (err) {
      setError('Failed to load systems');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container">
      <Navbar />
      <div className="main-content">
        <div className="page-header">
          <h1>Systems</h1>
          <p>Manage system records</p>
        </div>

        {error && <div className="error-message">{error}</div>}

        {loading ? (
          <div className="loading">Loading systems...</div>
        ) : (
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>System ID</th>
                  <th>System Name</th>
                  <th>Description</th>
                  <th>Business Function</th>
                  <th>Owner</th>
                </tr>
              </thead>
              <tbody>
                {systems.map((sys) => (
                  <tr key={sys.system_id}>
                    <td>{sys.system_id}</td>
                    <td>{sys.system_name}</td>
                    <td>{sys.description || '-'}</td>
                    <td>{sys.business_function}</td>
                    <td>{sys.owner_name}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Systems;

